solution: class Solution {
public:
    int addMinimum(string word) {
        int res = 0, expect = 0; // 0->'a', 1->'b', 2->'c'
        for (char c : word) {
            int cur = c - 'a';
            res += (cur - expect + 3) % 3;
            expect = (cur + 1) % 3;
        }
        res += (3 - expect) % 3;
        return res;
    }
};
